"const fs = require('fs');
const readline = require('readline');

const logPath = 'C:\\Users\\Rodrigo Daty\\.gemini\\antigravity-ide\\brain\\6d6172b2-ba3d-4a51-828b-ffa8b4ab5713\\.system_generated\\logs\\transcript.jsonl';

async function main() {
    const fileStream = fs.createReadStream(logPath);
    const rl = readline.createInterface({
        input: fileStream,
        crlfDelay: Infinity
    });

    for await (const line of rl) {
        if (!line.includes('analise-card')) continue;
        try {
            const obj = JSON.parse(line);
            console.log(`Step ${obj.step_index || 'unknown'}: type = ${obj.type}`);
            if (obj.tool_calls) {
                for (const tc of obj.tool_calls) {
                    console.log(`  Tool: ${tc.name}`);
                    if (tc.args && (tc.args.ReplacementContent || tc.args.CodeContent || tc.args.ReplacementChunks)) {
                        fs.writeFileSync(`scratch/log_found_step_${obj.step_index}.json`, JSON.stringify(tc.args, null, 2));
                        console.log(`    Wrote arguments to scratch/log_found_step_${obj.step_index}.json`);
                    }
                }
            }
        } catch (e) {}
    }
}

main().catch(console.error);
